const express = require('express');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');
const app = express();

// Create a write stream for logging
const accessLogStream = fs.createWriteStream(path.join(__dirname, 'access.log'), { flags: 'a' });

// Define custom logging format including username, IP, and custom headers
morgan.token('user', (req) => req.headers['username'] || 'guest');
morgan.token('custom-header', (req) => req.headers['x-custom-header'] || 'none');

app.use(morgan(':method :url :status :res[content-length] - :response-time ms | user: :user | IP: :remote-addr | custom-header: :custom-header', { stream: accessLogStream }));

app.use(express.json());

app.post('/submit', (req, res) => {
  const { data } = req.body;
  fs.appendFile('input.log', `User input: ${data}\n`, (err) => {
    if (err) throw err;
    res.send('Data received and logged');
  });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});